theorem totalize_run_mtr {xs : ωSequence Symbol} {ss : ωSequence (State ⊕ Unit)} {n : ℕ}
    (h : na.totalize.Run xs ss) (hl : (ss n).isLeft) :
    ∃ s t, na.MTr s (xs.take n) t ∧ s ∈ na.start ∧ ss 0 = inl s ∧ ss n = inl t :=

theorem totalize_mtr_run [Inhabited Symbol] {xl : List Symbol} {s t : State}
    (hs : s ∈ na.start) (hm : na.MTr s xl t) :
    ∃ xs ss, na.totalize.Run (xl ++ω xs) ss ∧ ss 0 = inl s ∧ ss xl.length = inl t :=

theorem iProd_run_iff {na : (i : I) → NA (State i) Symbol}
    {xs : ωSequence Symbol} {ss : ωSequence (Π i, State i)} :
    (iProd na).Run xs ss ↔ ∀ i, (na i).Run xs (ss.map (· i)) :=

theorem reindex_run_iff {f : State ≃ State'} {nba : Buchi State Symbol}
